import math
def bin_tail(m,p,k):
    return sum(math.comb(m,j)*p**j*(1-p)**(m-j) for j in range(k,m+1))
def lower_bound_expect(m,p):
    G=[None]+[bin_tail(m,p,k) for k in range(1,m+1)]
    # F_lower(k)
    F=[0]*(m+1)
    for k in range(1,m+1):
        F[k]=max(0,(k/m-p)/(1-p))
        if F[k]>1: F[k]=1
    # mass at k from F increments with F(0)=0
    return sum((F[k]-F[k-1])*G[k] for k in range(1,m+1)) + (1-F[m])*0
