def frac_good_fixed(x,a):
    b=len(x); cnt=0; tot=0
    thr=a/b - 1e-12
    for comb in itertools.combinations(range(b),a):
        tot+=1
        if sum(x[i] for i in comb)>=thr:
            cnt+=1
    return cnt/tot
